CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TYPE role_name AS ENUM ('user','seller','support_agent','administrator','manager');
CREATE TABLE accounts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), email TEXT NOT NULL UNIQUE, username TEXT NOT NULL UNIQUE, password_hash TEXT NOT NULL, avatar_url TEXT, email_verified BOOLEAN NOT NULL DEFAULT FALSE, terms_accepted BOOLEAN NOT NULL DEFAULT FALSE, is_blocked BOOLEAN NOT NULL DEFAULT FALSE, chat_restricted_until TIMESTAMPTZ, chat_blocked_forever BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE account_roles (account_id UUID NOT NULL REFERENCES accounts(id) ON DELETE CASCADE, role role_name NOT NULL, granted_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), PRIMARY KEY (account_id, role));
CREATE TABLE email_verifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), account_id UUID NOT NULL REFERENCES accounts(id) ON DELETE CASCADE, token TEXT NOT NULL UNIQUE, used BOOLEAN NOT NULL DEFAULT FALSE, expires_at TIMESTAMPTZ NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE listings (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), seller_id UUID NOT NULL REFERENCES accounts(id) ON DELETE CASCADE, title TEXT NOT NULL, description TEXT NOT NULL, price NUMERIC(12,2) NOT NULL CHECK (price >= 0), is_active BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE listing_images (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), listing_id UUID NOT NULL REFERENCES listings(id) ON DELETE CASCADE, url TEXT NOT NULL, position SMALLINT NOT NULL CHECK (position BETWEEN 1 AND 9), UNIQUE (listing_id, position));
CREATE TABLE chats (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE chat_participants (chat_id UUID NOT NULL REFERENCES chats(id) ON DELETE CASCADE, account_id UUID NOT NULL REFERENCES accounts(id) ON DELETE CASCADE, PRIMARY KEY (chat_id, account_id));
CREATE TABLE messages (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), chat_id UUID NOT NULL REFERENCES chats(id) ON DELETE CASCADE, sender_id UUID NOT NULL REFERENCES accounts(id) ON DELETE CASCADE, content TEXT NOT NULL, sent_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE refresh_tokens (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), account_id UUID NOT NULL REFERENCES accounts(id) ON DELETE CASCADE, token_hash TEXT NOT NULL UNIQUE, expires_at TIMESTAMPTZ NOT NULL, revoked BOOLEAN NOT NULL DEFAULT FALSE);
